import sys

def nearest_smaller_to_left(A):
    """Compute the sum of nearest-smaller-to-the-left values."""
    n = len(A)
    L = [-1] * n
    stack = []

    for i in range(n):
        while stack and A[stack[-1]] >= A[i]:
            stack.pop()
        if stack:
            L[i] = A[stack[-1]]
        stack.append(i)

    return sum(L)

def main():
    """Read input from stdin and write the answer to stdout."""
    n = int(sys.stdin.readline())
    A = list(map(int, sys.stdin.readline().split()))

    result = nearest_smaller_to_left(A)
    print(result)

if __name__ == "__main__":
