import sys

d = sys.stdin.buffer.read().split()
n = int(d[0])
a = [int(x) for x in d[1:1 + n]]

def nearest_smaller_to_left(a):
    stack = []
    result = []

    for i in range(len(a)):
        while len(stack) > 0 and a[stack[-1]] >= a[i]:
            stack.pop()
        if len(stack) == 0:
            result.append(-1)
        else:
            result.append(a[stack[-1]])
        stack.append(i)

    return result

def sum_of_nearest_smaller_to_left(a):
    result = nearest_smaller_to_left(a)
    return sum(result)

print(sum_of_nearest_smaller_to_left(a))
